import numpy as np

def check(arr):
    if arr.ndim != 1 or arr.dtype != np.float64:
        raise ValueError("expected 1d float64")
    return f"ok {arr.size}"

out_ok = check(np.array([1.0, 2.0], dtype=np.float64))
try:
    check(np.array([[1.0]]))
    err = ""
except ValueError as e:
    err = f"err {e}"
print(f"{out_ok} | {err}")

